var e=[{id:`L3_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`흐아아… 너, 너무 돌아서 어지러워요.`,JPN:`ふああ……ま、回りすぎて目眩がします。`,ENG:`Ahhh... W-we spun around so much, I'm feeling dizzy.`,TWN:`哼哼……你轉得我頭暈眼花。`},stage:{bg:`CAR`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L4_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`골목이 좁아서 그래.`,JPN:`道が狭いからだよ。`,ENG:`It's because the alley is narrow.`,TWN:`沒辦法，這是一條窄巷。`},stage:{bg:`CAR`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_HATE`},C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L5_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`꽉 잡아!`,JPN:`しっかり掴まれ！`,ENG:`Hold on tight!`,TWN:`抓緊了！`},stage:{bg:`CAR`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_HATE`},C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`},R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L8_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`…우와와! 방금 차 뒤집힐 뻔했어!`,JPN:`……わわっ！　今、車がひっくり返そうになったわよ！？`,ENG:`...Whoa! The car almost flipped!`,TWN:`……哇啊啊！差點翻車了！`},stage:{bg:`CAR`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`라이카! 미쳤어요?! 방금 제 방패로 무게 중심 안 잡았으면 그대로 전복됐을 거라고요!`,JPN:`ライカ！　正気なの！？　今私の盾でバランスを取らなかったら、そのまま横転してたよ！`,ENG:`Are you crazy, Laika?! If I hadn't used my shield to center the car, we would've flipped!`,TWN:`萊卡，你瘋了嗎？！要不是用我的盾牌保持平衡，我們真的就翻車了！`},stage:{bg:`CAR`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L10_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`나이스 팀워크!`,JPN:`ナイスチームワーク！`,ENG:`Nice teamwork!`,TWN:`絕好的配合！`},stage:{bg:`CAR`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L11_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`나… 나이스…!`,JPN:`な……ナイス……！`,ENG:`N-nice...!`,TWN:`好……好耶……！`},stage:{bg:`CAR`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_HATE`},C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L12_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`나이스는 무슨!`,JPN:`どこがよ！`,ENG:`Not nice! No!`,TWN:`好個屁！`},stage:{bg:`CAR`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_HATE`},C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L13_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`이번엔 계단으로 간다!`,JPN:`今度は階段だ！`,ENG:`We're heading toward the stairs!`,TWN:`這次是樓梯！`},stage:{bg:`CAR`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_HATE`},C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_PRIDE`},R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`}}}},{id:`L26_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`크읏…!`,JPN:`ぐうっ……！`,ENG:`Kgh...!`,TWN:`咳……！`},stage:{bg:`CAR`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`휴우- 노엘은 괜찮…?`,JPN:`ふう～ノエルは大丈……？`,ENG:`Phew, are you all right, Noelle–`,TWN:`呼，洛艾兒還好嗎……？`},stage:{bg:`CAR`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`…아앗!`,JPN:`……ああっ！`,ENG:`...Ahh!`,TWN:`……哎唷！`},stage:{bg:`CAR`,slots:{L:null,C:null,R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L31_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`노엘 머리가 차지붕을 뚫고 올라갔다!`,JPN:`ノエルの頭が車の屋根を貫通しちゃってるわ！`,ENG:`Noelle's head is through the roof of the car!`,TWN:`洛艾兒的腦袋撞破車頂了！`},stage:{bg:`CAR`,slots:{L:null,C:null,R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L32_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`아, 미안. 안전벨트 한 줄 알았지.`,JPN:`あ、わりぃ。シートベルトしてると思ってたよ。`,ENG:`Ah, my bad. I thought you had your seatbelt on.`,TWN:`喔，對不起。我以為你繫好了安全帶。`},stage:{bg:`CAR`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_SURPRISE`},R:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L35_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`으으… 머리야. 속이 안 좋아.`,JPN:`うう……頭痛い……吐きそう……`,ENG:`Ngh... My head. I feel sick.`,TWN:`呃……我的腦袋，好想吐喔。`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_HATE`},R:null}}}];export{e as default};